      <h3 className="mt-3 mb-2">{product.name}</h3>
      <p className="font-bold text-[#0070f3]">${product.price.toFixed(2)}</p>
      <button className="w-full p-2.5 mt-3 bg-[#0070f3] text-white border-none rounded cursor-pointer">
        Add to Cart
      </button>
    </div>
  );
}
